+    #[test]
+    fn test_retryable_checks() {
+        // Retryable
+        assert!(
+            GoogleCalendarError::RateLimited {
+                retry_after_secs: 1
+            }
+            .is_retryable()
+        );
+        assert!(
+            GoogleCalendarError::Api {
+                code: 429,
+                message: String::new()
